 1	import * as React from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Text, TextVariants } from '@patternfly/react-core';
 6	
 7	import { HARDWARE_DEVICE_TYPE } from '../utils/constants';
 8	
 9	type HardwareDevicesModalProps = {
10	  type: HARDWARE_DEVICE_TYPE.GPUS | HARDWARE_DEVICE_TYPE.HOST_DEVICES;
11	};
12	const HardwareDeviceModalDescription: React.FC<HardwareDevicesModalProps> = ({ type }) => {
13	  const { t } = useKubevirtTranslation();
14	
15	  return (
16	    <Text className="text-muted" component={TextVariants.p}>
17	      <Trans ns="plugin__kubevirt-plugin" t={t}>
18	        Enter a name for the device to be assigned and select it from the dropdown menu. Click{' '}
19	        <b> Save</b>.<br /> Click{' '}
20	        <b>+ Add {{ hardwareType: type === HARDWARE_DEVICE_TYPE.GPUS ? 'GPU' : 'Host' }} device</b>{' '}
21	        to add another devices.
22	      </Trans>
23	    </Text>
24	  );
25	};
26	export default HardwareDeviceModalDescription;

